const pool = new Pool({
  user: 'username',
  host: 'localhost',
  database: 'database',
  password: 'password',
  port: 5432,
  maxConnections: 50, // Increased pool size
  connectionTimeoutMillis: 5000, // Set a timeout for connection establishment
